private struct KindleTabHost<Content: View>: View {
    let title: String
    let icon: String
    @ViewBuilder var content: () -> Content
    var body: some View { content() }
}

private enum KindleScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("library") || t.contains("biblioth") || t.contains("home") || t.contains("accueil"):
            KindleLibraryScreen()
        case let t where t.contains("discover") || t.contains("découvr") || t.contains("search"):
            KindleDiscoverScreen()
        default:
            KindleGenericListScreen(title: tab)
        }
    }
}
