private struct KindleLibraryScreen: View {
    var body: some View {
        NavigationStack {
            List(KindleDemoData.books) { book in
                HStack(spacing: 14) {
                    RoundedRectangle(cornerRadius: 4).fill(book.color).frame(width: 48, height: 72)
                    VStack(alignment: .leading, spacing: 4) {
                        Text(book.title).font(.headline)
                        Text(book.author).font(.subheadline).foregroundStyle(.secondary)
                        ProgressView(value: book.progress).tint(KindleTokens.kdlOrange)
                        Text("\(Int(book.progress * 100)) % lu").font(.caption).foregroundStyle(.secondary)
                    }
                }
            }.navigationTitle("Bibliothèque")
        }
    }
}

private struct KindleDiscoverScreen: View {
    var body: some View { NavigationStack { Text("Découvrir de nouveaux livres").padding().navigationTitle("Découvrir") } }
}

private struct KindleBook: Identifiable { let id = UUID(); let title: String; let author: String; let progress: Double; let color: Color }
